class Solution:
    def maximumScore(self, a, b, c):
        piles = [a, b, c]
        score = 0
        while True:
            piles.sort()
            if piles[1] == 0:
                break
            piles[1] -= 1
            piles[2] -= 1
            score += 1
        return score

